247	const State = struct {
248	    // The effective buffer to process Vietnamese input. we will skip processing if the buffer
249	    // longer than 16.
250	    buffer_effective: [16]Span,
251	    // The maximum buffer length that the engine still keeps the effective buffer, after the maximum
252	    // value (255), we will reset the effective buffer and this value.
253	    buffer_length: u8 = 0,
254	    // Mark the earliest position (inclusive) in buffer where we modified the span, will be used to
255	    // calculate backspaces and replacement characters.
256	    buffer_modification_index: ?u8 = null,
257	    // Mark the position (inclusive) in buffer where the engine stops Telex processing and appends
258	    // the remaining composition literally. Positions before literal_index were processed as Telex;
259	    // positions on or after literal_index form the literal tail. null means the whole current buffer
260	    // remains Telex-processable.
261	    literal_index: ?u8 = null,
262	
263	    // Initialize the State on allocated memory.
264	    fn init(self: *State) void {
265	        self.* = .{
266	            .buffer_effective = undefined,
267	        };
268	    }
269	
270	    fn add(self: *State, c: u8) void {
271	        // Only allow a-zA-Z.
272	        assert(isAlphabetic(c));
273	
274	        if (self.literal_index) |literal_index| {
275	            // The literal_index value must be in range null or 0 -> 16 (buffer_effective length)
276	            // because we won't process Vietnamese input outside the buffer_effective.
277	            assert(literal_index <= self.buffer_effective.len);
278	            // The literal_index value must be less than buffer length.
279	            assert(literal_index < self.buffer_length);
280	        }
